#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

class ComplexNumber {
private:
    double real;
    double imaginary;

public:
    ComplexNumber(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}

    double getReal() const { return real; }
    double getImaginary() const { return imaginary; }

    ComplexNumber operator+(const ComplexNumber& other) {
        this->real += other.real;
        this->imaginary += other.imaginary;
        return *this;
    }

    std::string toString() const {
        std::ostringstream oss;
        oss << std::fixed << std::setprecision(2);
        oss << real;
        if (imaginary >= 0) {
            oss << "+" << imaginary << "i";
        } else {
            oss << imaginary << "i";
        }
        return oss.str();
    }
};

int main() {
    ComplexNumber c1(1.0, 2.0); ComplexNumber c2(3.0, 4.0); ComplexNumber result_tc1 = c1 + c2; std::cout << result_tc1.toString() << std::endl; std::cout << c1.toString() << std::endl;
    ComplexNumber c3(-0.5, 1.5); ComplexNumber c4(2.5, -3.5); ComplexNumber result_tc2 = c3 + c4; std::cout << result_tc2.toString() << std::endl; std::cout << c3.toString() << std::endl;
    ComplexNumber cx1(1.0, 1.0); ComplexNumber cx2(2.0, 2.0); ComplexNumber cx3(3.0, 3.0); ComplexNumber result_tc3 = cx1 + cx2 + cx3; std::cout << result_tc3.toString() << std::endl; std::cout << cx1.toString() << std::endl;
    return 0;
}
